import React, { useState, useEffect, useLayoutEffect, useRef, useMemo, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { Text } from '@/components/Text';
import { Surface } from '@/components/Surface';
import { MenuItem as MenuItemComponent } from './MenuItem';
import { DestructiveMenuItem } from './DestructiveMenuItem';
import { getCssSpacePx } from '@/utils/css-tokens';
import type { IconComponent } from '@/types';
import type { MenuItemSelectionStyle } from './MenuItem';
import styles from './Menu.module.css';

const CLOSE_ANIMATION_MS = 220;

export type MenuSide = 'top' | 'right' | 'bottom' | 'left';
export type MenuAlign = 'start' | 'center' | 'end';

export interface MenuItemData {
  label: string;
  onClick: () => void;
  isSelected?: boolean;
  isDestructive?: boolean;
  isInactive?: boolean;
  intent?: 'negative';
  keepOpenOnClick?: boolean;
  holdDuration?: number;
  icon?: IconComponent;
  subtext?: string;
  showToggle?: boolean;
  toggleValue?: boolean;
  selectionStyle?: MenuItemSelectionStyle;
}

export interface MenuSection {
  header?: string;
  items: MenuItemData[];
}

export interface MenuProps {
  isOpen: boolean;
  onClose: () => void;
  anchorRef: React.RefObject<HTMLElement | null>;
  items?: MenuItemData[];
  sections?: MenuSection[];
  side?: MenuSide;
  align?: MenuAlign;
  sideOffset?: number;
  alignOffset?: number;
  sideOffsetToken?: string;
  alignOffsetToken?: string;
  width?: string;
  minWidth?: string;
  maxWidth?: string;
  matchAnchorWidth?: boolean;
  matchAnchorWidthOffset?: number;
  usePortal?: boolean;
  ariaLabel?: string;
}

export const Menu: React.FC<MenuProps> = ({
  isOpen,
  onClose,
  anchorRef,
  items,
  sections,
  side = 'bottom',
  align = 'start',
  sideOffset = 4,
  alignOffset = 0,
  sideOffsetToken,
  alignOffsetToken,
  width,
  minWidth,
  maxWidth,
  matchAnchorWidth = false,
  matchAnchorWidthOffset = 0,
  usePortal = true,
  ariaLabel = 'Menu',
}) => {
  const [isClosing, setIsClosing] = useState(false);
  const [shouldRender, setShouldRender] = useState(isOpen);
  const [isPositionReady, setIsPositionReady] = useState(false);
  const [position, setPosition] = useState<{ x: number; y: number }>({ x: 0, y: 0 });
  const [menuSize, setMenuSize] = useState<{ width: number; height: number }>({ width: 0, height: 0 });
  const [anchorSize, setAnchorSize] = useState<{ width: number; height: number }>({ width: 0, height: 0 });
  const [focusedIndex, setFocusedIndex] = useState(0);
  const positionCalculatedRef = useRef(false);
  const menuRef = useRef<HTMLDivElement>(null);
  const lastSectionsRef = useRef<MenuSection[]>([]);
  const itemRefs = useRef<Array<HTMLButtonElement | null>>([]);
  const focusedOnOpenRef = useRef(false);

  const menuSections: MenuSection[] = sections || (items ? [{ items }] : []);

  const hasItems = menuSections.some((s) => s.items.length > 0);
  if (!isClosing && menuSections.length > 0 && hasItems) {
    lastSectionsRef.current = menuSections;
  }
  const sectionsToRender = isClosing ? lastSectionsRef.current : menuSections;

  const flatItems = useMemo(() => {
    const list: MenuItemData[] = [];
    sectionsToRender.forEach((section) => {
      section.items.forEach((it) => list.push(it));
    });
    return list;
  }, [sectionsToRender]);

  useEffect(() => {
    if (isOpen) {
      setShouldRender(true);
      setIsClosing(false);
      setIsPositionReady(false);
      positionCalculatedRef.current = false;
    } else if (shouldRender) {
      setIsClosing(true);
      const timer = setTimeout(() => {
        setShouldRender(false);
        setIsClosing(false);
        positionCalculatedRef.current = false;
      }, CLOSE_ANIMATION_MS);
      return () => clearTimeout(timer);
    }
  }, [isOpen, shouldRender]);

  useLayoutEffect(() => {
    if (!isOpen || !shouldRender || !menuRef.current) return;
    const updateSize = () => {
      if (!menuRef.current) return;
      const rect = menuRef.current.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) setMenuSize({ width: rect.width, height: rect.height });
    };
    updateSize();
    requestAnimationFrame(() => requestAnimationFrame(updateSize));
    if (typeof ResizeObserver !== 'undefined') {
      const observer = new ResizeObserver(updateSize);
      observer.observe(menuRef.current);
      return () => observer.disconnect();
    }
  }, [isOpen, shouldRender, menuSections.length]);

  useLayoutEffect(() => {
    if (!isOpen || !shouldRender || !anchorRef.current || !menuRef.current) return;
    const calculatePosition = () => {
      const anchor = anchorRef.current;
      const menu = menuRef.current;
      if (!anchor || !menu) return;
      const anchorRect = anchor.getBoundingClientRect();
      const menuRect = menu.getBoundingClientRect();
      const menuWidth = menuRect.width || menuSize.width || 200;
      const menuHeight = menuRect.height || menuSize.height || 160;
      setAnchorSize({ width: anchorRect.width, height: anchorRect.height });
      const gap = sideOffsetToken != null ? getCssSpacePx(sideOffsetToken, 12) : sideOffset;
      const alignOff = alignOffsetToken != null ? getCssSpacePx(alignOffsetToken, 4) : alignOffset;
      let x = 0, y = 0;
      switch (side) {
        case 'top':
          y = anchorRect.top - menuHeight - gap;
          x = align === 'start' ? anchorRect.left + alignOff : align === 'end' ? anchorRect.right - menuWidth + alignOff : anchorRect.left + anchorRect.width / 2 - menuWidth / 2 + alignOff;
          break;
        case 'bottom':
          y = anchorRect.bottom + gap;
          x = align === 'start' ? anchorRect.left + alignOff : align === 'end' ? anchorRect.right - menuWidth + alignOff : anchorRect.left + anchorRect.width / 2 - menuWidth / 2 + alignOff;
          break;
        case 'left':
          x = anchorRect.left - menuWidth - gap;
          y = align === 'start' ? anchorRect.top + alignOff : align === 'end' ? anchorRect.bottom - menuHeight + alignOff : anchorRect.top + anchorRect.height / 2 - menuHeight / 2 + alignOff;
          break;
        case 'right':
          x = anchorRect.right + gap;
          y = align === 'start' ? anchorRect.top + alignOff : align === 'end' ? anchorRect.bottom - menuHeight + alignOff : anchorRect.top + anchorRect.height / 2 - menuHeight / 2 + alignOff;
          break;
      }
      const vp = 4;
      setPosition({
        x: Math.min(Math.max(x, vp), window.innerWidth - menuWidth - vp),
        y: Math.min(Math.max(y, vp), window.innerHeight - menuHeight - vp),
      });
      positionCalculatedRef.current = true;
      setIsPositionReady(true);
    };
    if (!positionCalculatedRef.current) {
      calculatePosition();
      requestAnimationFrame(() => { if (!positionCalculatedRef.current) calculatePosition(); });
    }
    const handleScrollResize = () => calculatePosition();
    window.addEventListener('scroll', handleScrollResize, true);
    window.addEventListener('resize', handleScrollResize);
    return () => {
      window.removeEventListener('scroll', handleScrollResize, true);
      window.removeEventListener('resize', handleScrollResize);
    };
  }, [isOpen, shouldRender, anchorRef, side, align, sideOffset, alignOffset, sideOffsetToken, alignOffsetToken, menuSize.width, menuSize.height, menuSections.length, matchAnchorWidthOffset]);

  const closeAndRestoreFocus = useCallback(() => {
    const active = document.activeElement as HTMLElement | null;
    const focusInside = !!(active && menuRef.current?.contains(active));
    if (focusInside && anchorRef.current) {
      anchorRef.current.focus();
    }
    onClose();
  }, [onClose, anchorRef]);

  useEffect(() => {
    if (!isOpen || !shouldRender) return;
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      if (menuRef.current?.contains(target)) return;
      if (anchorRef.current?.contains(target)) return;
      onClose();
    };
    document.addEventListener('mousedown', handleClickOutside, true);
    return () => document.removeEventListener('mousedown', handleClickOutside, true);
  }, [isOpen, shouldRender, onClose, anchorRef]);

  useEffect(() => {
    if (!isOpen) return;
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.preventDefault();
        closeAndRestoreFocus();
      }
    };
    document.addEventListener('keydown', handleEscape);
    return () => document.removeEventListener('keydown', handleEscape);
  }, [isOpen, closeAndRestoreFocus]);

  useEffect(() => {
    if (!isOpen) {
      focusedOnOpenRef.current = false;
      return;
    }
    if (!isPositionReady || focusedOnOpenRef.current) return;
    const firstEnabled = flatItems.findIndex((it) => !it.isInactive);
    const targetIdx = firstEnabled >= 0 ? firstEnabled : 0;
    setFocusedIndex(targetIdx);
    itemRefs.current[targetIdx]?.focus();
    focusedOnOpenRef.current = true;
  }, [isOpen, isPositionReady, flatItems]);

  const moveFocus = useCallback((idx: number) => {
    setFocusedIndex(idx);
    itemRefs.current[idx]?.focus();
  }, []);

  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLDivElement>) => {
    if (!flatItems.length) return;
    const enabled: number[] = [];
    flatItems.forEach((it, i) => { if (!it.isInactive) enabled.push(i); });
    if (!enabled.length) return;
    const currentPos = enabled.indexOf(focusedIndex);
    const safePos = currentPos < 0 ? 0 : currentPos;

    switch (e.key) {
      case 'ArrowDown': {
        e.preventDefault();
        e.stopPropagation();
        moveFocus(enabled[(safePos + 1) % enabled.length]);
        break;
      }
      case 'ArrowUp': {
        e.preventDefault();
        e.stopPropagation();
        moveFocus(enabled[(safePos - 1 + enabled.length) % enabled.length]);
        break;
      }
      case 'Home': {
        e.preventDefault();
        e.stopPropagation();
        moveFocus(enabled[0]);
        break;
      }
      case 'End': {
        e.preventDefault();
        e.stopPropagation();
        moveFocus(enabled[enabled.length - 1]);
        break;
      }
      case 'Tab': {
        e.preventDefault();
        closeAndRestoreFocus();
        break;
      }
    }
  }, [flatItems, focusedIndex, moveFocus, closeAndRestoreFocus]);

  if (!shouldRender || sectionsToRender.length === 0) return null;

  const setItemRef = (flatIndex: number) => (el: HTMLButtonElement | null) => {
    itemRefs.current[flatIndex] = el;
  };

  const handleItemFocus = (flatIndex: number) => () => {
    setFocusedIndex(flatIndex);
  };

  const renderMenuItem = (item: MenuItemData, flatIndex: number) => {
    const tabIndex = focusedIndex === flatIndex ? 0 : -1;
    if (item.isDestructive) {
      return (
        <DestructiveMenuItem
          key={flatIndex}
          ref={setItemRef(flatIndex)}
          label={item.label}
          subtext={item.subtext}
          holdDuration={item.holdDuration ?? 4000}
          onClick={() => { item.onClick(); if (!item.keepOpenOnClick) closeAndRestoreFocus(); }}
          tabIndex={tabIndex}
          onFocus={handleItemFocus(flatIndex)}
        />
      );
    }
    return (
      <MenuItemComponent
        key={flatIndex}
        ref={setItemRef(flatIndex)}
        icon={item.icon}
        label={item.label}
        subtext={item.subtext}
        onClick={() => { if (!item.isInactive) { item.onClick(); if (!item.keepOpenOnClick) closeAndRestoreFocus(); } }}
        isSelected={item.isSelected}
        isInactive={item.isInactive}
        intent={item.intent}
        showToggle={item.showToggle}
        toggleValue={item.toggleValue}
        selectionStyle={item.selectionStyle}
        tabIndex={tabIndex}
        onFocus={handleItemFocus(flatIndex)}
      />
    );
  };

  const menuStyle: React.CSSProperties = {
    position: 'absolute',
    left: 0,
    top: 0,
    transform: `translate(${Math.round(position.x)}px, ${Math.round(position.y)}px)`,
    willChange: 'transform',
    zIndex: 9998,
    visibility: isPositionReady ? 'visible' : 'hidden',
    ...(matchAnchorWidth && anchorSize.width > 0 ? { width: `${anchorSize.width + matchAnchorWidthOffset}px` } : width ? { width } : {}),
    ...(minWidth ? { minWidth } : {}),
    ...(maxWidth ? { maxWidth } : {}),
  };

  let runningIdx = 0;

  const menuContent = (
    <div
      ref={menuRef}
      className={`${styles.menuContainer} ${isClosing ? styles.closing : ''}`}
      style={menuStyle}
      role="menu"
      aria-label={ariaLabel}
      aria-orientation="vertical"
      onKeyDown={handleKeyDown}
    >
      {sectionsToRender.map((section, sectionIndex) => {
        const sectionStart = runningIdx;
        runningIdx += section.items.length;
        return (
          <Surface
            key={sectionIndex}
            as="div"
            className={styles.menuSection}
            edge={sectionIndex < sectionsToRender.length - 1 ? 'bottom' : undefined}
            elevation="none"
            role={section.header ? 'group' : undefined}
            aria-label={section.header}
          >
            {section.header && (
              <div className={styles.sectionHeader} aria-hidden="true">
                <Text variant="text-body-small-emphasis" as="span" className={styles.sectionLabel}>{section.header}</Text>
              </div>
            )}
            {section.items.map((item, itemIndex) => renderMenuItem(item, sectionStart + itemIndex))}
          </Surface>
        );
      })}
    </div>
  );

  if (usePortal) return createPortal(menuContent, document.body);
  return menuContent;
};

Menu.displayName = 'Menu';

.menuContainer {
  box-sizing: border-box;
  background-color: var(--color-background-primary);
  border-radius: var(--dimension-radius-125);
  box-shadow: var(--effect-elevation-elevated-floating);
  display: flex;
  flex-direction: column;
  min-width: 200px;
  max-width: 600px;
  overflow: hidden;
  animation: menuFadeIn var(--effect-motion-short-2) forwards;
  backface-visibility: hidden;
  -webkit-font-smoothing: subpixel-antialiased;
}

@keyframes menuFadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.menuContainer.closing {
  animation: menuFadeOut var(--effect-motion-short-3) forwards;
}

@keyframes menuFadeOut {
  from { opacity: 1; }
  to { opacity: 0; }
}

.menuSection {
  padding: var(--dimension-space-050);
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-050);
}

.sectionHeader {
  padding: var(--dimension-space-050) var(--dimension-space-075);
  display: flex;
  align-items: center;
  height: var(--dimension-size-400);
  -webkit-user-select: none;
  user-select: none;
}

.sectionLabel {
  color: var(--color-foreground-secondary);
  text-align: left;
}

import React, { forwardRef } from 'react';
import { Text } from '@/components/Text';
import { Surface } from '@/components/Surface';
import type { IconComponent } from '@/types';
import styles from './MenuItem.module.css';

export type MenuItemSelectionStyle = 'highlight' | 'radio' | 'noOverlay';

export type MenuItemRole = 'menuitem' | 'menuitemcheckbox' | 'menuitemradio';

export interface MenuItemProps {
  label: string;
  onClick: () => void;
  isSelected?: boolean;
  isInactive?: boolean;
  icon?: IconComponent;
  labelColor?: 'primary' | 'secondary' | 'tertiary';
  subtext?: string;
  showToggle?: boolean;
  toggleValue?: boolean;
  intent?: 'negative';
  selectionStyle?: MenuItemSelectionStyle;
  showTrailingChevron?: boolean;
  checkIcon?: IconComponent;
  chevronIcon?: IconComponent;
  tabIndex?: number;
  onKeyDown?: (e: React.KeyboardEvent<HTMLButtonElement>) => void;
  onFocus?: (e: React.FocusEvent<HTMLButtonElement>) => void;
}

export const MenuItem = forwardRef<HTMLButtonElement, MenuItemProps>(
  ({
    label,
    onClick,
    isSelected = false,
    isInactive = false,
    icon: Icon,
    labelColor,
    subtext,
    showToggle = false,
    toggleValue = false,
    intent,
    selectionStyle = 'highlight',
    showTrailingChevron = false,
    checkIcon: CheckIcon,
    chevronIcon: ChevronIcon,
    tabIndex,
    onKeyDown,
    onFocus,
  }, ref) => {
    const useRadioStyle = selectionStyle === 'radio';
    const noOverlay = selectionStyle === 'noOverlay' || useRadioStyle;
    const showSelectedOverlay = isSelected && !noOverlay;

    const role: MenuItemRole = showToggle
      ? 'menuitemcheckbox'
      : useRadioStyle
        ? 'menuitemradio'
        : 'menuitem';

    const ariaChecked: boolean | undefined =
      role === 'menuitemcheckbox'
        ? !!toggleValue
        : role === 'menuitemradio'
          ? !!isSelected
          : undefined;

    return (
      <Surface
        ref={ref as React.Ref<HTMLElement>}
        as="button"
        interactive={!isInactive}
        selected={showSelectedOverlay}
        radius="sm"
        className={`${styles.menuItem} ${isSelected ? styles.menuItemSelected : ''} ${isInactive ? styles.menuItemInactive : ''} ${intent === 'negative' ? styles.menuItemNegative : ''} ${labelColor === 'tertiary' ? styles.menuItemLabelTertiary : ''}`}
        onClick={onClick}
        type="button"
        inactive={isInactive}
        role={role}
        tabIndex={tabIndex ?? -1}
        aria-checked={ariaChecked}
        aria-disabled={isInactive || undefined}
        onKeyDown={onKeyDown}
        onFocus={onFocus}
      >
        {Icon && (
          <div className={styles.iconPrefix} aria-hidden="true">
            <Icon size={20} />
          </div>
        )}
        <div className={styles.content}>
          <Text
            variant={isSelected ? 'text-body-medium-emphasis' : 'text-body-medium'}
            color={labelColor}
            as="span"
            className={styles.label}
          >
            {label}
          </Text>
          {subtext && (
            <Text variant="text-body-small" as="span" className={styles.subtext}>
              {subtext}
            </Text>
          )}
        </div>
        {showToggle && (
          <div className={styles.toggleSuffix} aria-hidden="true">
            <div className={`${styles.toggle} ${toggleValue ? styles.toggleOn : ''}`}>
              <div className={styles.toggleThumb} />
            </div>
          </div>
        )}
        {useRadioStyle && isSelected && CheckIcon && (
          <div className={styles.checkSuffix} aria-hidden="true">
            <CheckIcon size={20} />
          </div>
        )}
        {showTrailingChevron && ChevronIcon && (
          <div className={styles.chevronSuffix} aria-hidden="true">
            <ChevronIcon size={20} />
          </div>
        )}
      </Surface>
    );
  }
);

MenuItem.displayName = 'MenuItem';

.menuItem {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
  padding: var(--dimension-space-075);
  border: none;
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  text-align: left;
  width: 100%;
  min-height: var(--dimension-size-400);
}

.menuItem:has(.subtext) { align-items: flex-start; }

.iconPrefix {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  color: var(--color-foreground-secondary);
}

.menuItemSelected .iconPrefix { color: var(--color-foreground-primary); }

.content {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-025);
  min-width: 0;
}

.label { color: var(--color-foreground-secondary); }
.menuItem:has(.subtext) .label { color: var(--color-foreground-primary); }
.menuItemSelected .label { color: var(--color-foreground-primary) !important; }
.menuItemLabelTertiary .label, .menuItemLabelTertiary .iconPrefix { color: var(--color-foreground-tertiary); }
.menuItemNegative .label { color: var(--color-foreground-bold-negative) !important; }

.subtext { color: var(--color-foreground-secondary); line-height: 1.4; }

.menuItemInactive { opacity: 0.5; cursor: default; pointer-events: none; }

.toggleSuffix { flex-shrink: 0; display: flex; align-items: center; }

.toggle {
  width: calc(var(--dimension-size-400) + var(--dimension-size-050));
  height: var(--dimension-size-250);
  background-color: var(--color-background-translucent);
  border-radius: var(--dimension-radius-125);
  position: relative;
  transition: var(--effect-transition-interaction-background-short-2);
}

.toggleOn { background-color: var(--color-background-medium-brand); }

.toggleThumb {
  width: var(--dimension-size-200);
  height: var(--dimension-size-200);
  background-color: var(--color-foreground-on-bold-background-primary);
  border-radius: 50%;
  position: absolute;
  top: var(--dimension-space-025);
  left: var(--dimension-space-025);
  transition: transform var(--effect-motion-short-2);
}

.toggleOn .toggleThumb { transform: translateX(var(--dimension-offset-200)); }

.checkSuffix {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  color: var(--color-foreground-primary);
}

.chevronSuffix {
  flex-shrink: 0;
  display: flex;
  align-items: center;
  color: var(--color-foreground-secondary);
}

.menuItemSelected .chevronSuffix { color: var(--color-foreground-primary); }

import React, { forwardRef, useState, useRef, useEffect } from 'react';
import { Text } from '@/components/Text';
import styles from './DestructiveMenuItem.module.css';

export interface DestructiveMenuItemProps {
  label: string;
  onClick: () => void;
  holdDuration?: number;
  subtext?: string;
  tabIndex?: number;
  onKeyDown?: (e: React.KeyboardEvent<HTMLButtonElement>) => void;
  onFocus?: (e: React.FocusEvent<HTMLButtonElement>) => void;
}

export const DestructiveMenuItem = forwardRef<HTMLButtonElement, DestructiveMenuItemProps>(
  ({ label, onClick, holdDuration = 4000, subtext, tabIndex, onKeyDown, onFocus }, ref) => {
    const [progress, setProgress] = useState(0);
    const pressTimerRef = useRef<number | null>(null);
    const startTimeRef = useRef<number>(0);
    const animationFrameRef = useRef<number | null>(null);
    const isHoldingRef = useRef(false);

    const resetState = () => {
      setProgress(0);
      isHoldingRef.current = false;
      if (pressTimerRef.current) { clearTimeout(pressTimerRef.current); pressTimerRef.current = null; }
      if (animationFrameRef.current) { cancelAnimationFrame(animationFrameRef.current); animationFrameRef.current = null; }
    };

    const startHold = () => {
      if (isHoldingRef.current) return;
      isHoldingRef.current = true;
      if (holdDuration === 0) { onClick(); resetState(); return; }
      startTimeRef.current = performance.now();
      const animate = () => {
        const elapsed = performance.now() - startTimeRef.current;
        const newProgress = Math.min((elapsed / holdDuration) * 100, 100);
        setProgress(newProgress);
        if (newProgress < 100) animationFrameRef.current = requestAnimationFrame(animate);
      };
      animationFrameRef.current = requestAnimationFrame(animate);
      pressTimerRef.current = window.setTimeout(() => { onClick(); resetState(); }, holdDuration);
    };

    const handleMouseDown = (e: React.MouseEvent) => {
      e.stopPropagation();
      e.preventDefault();
      startHold();
    };

    const handleMouseUp = (e: React.MouseEvent) => { e.stopPropagation(); resetState(); };
    const handleMouseLeave = (e: React.MouseEvent) => { e.stopPropagation(); resetState(); };

    const isSpaceKey = (e: React.KeyboardEvent) => e.key === ' ' || e.key === 'Spacebar';

    const handleKeyDown = (e: React.KeyboardEvent<HTMLButtonElement>) => {
      if (isSpaceKey(e)) {
        e.preventDefault();
        if (e.repeat) return;
        e.stopPropagation();
        startHold();
        return;
      }
      if (e.key === 'Enter') {
        e.preventDefault();
        return;
      }
      onKeyDown?.(e);
    };

    const handleKeyUp = (e: React.KeyboardEvent<HTMLButtonElement>) => {
      if (isSpaceKey(e)) {
        e.preventDefault();
        e.stopPropagation();
        resetState();
      }
    };

    const handleBlur = () => { resetState(); };

    useEffect(() => () => { resetState(); }, []);

    return (
      <button
        ref={ref}
        className={styles.destructiveMenuItem}
        onMouseDown={handleMouseDown}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseLeave}
        onKeyDown={handleKeyDown}
        onKeyUp={handleKeyUp}
        onBlur={handleBlur}
        onFocus={onFocus}
        type="button"
        role="menuitem"
        tabIndex={tabIndex ?? -1}
        aria-keyshortcuts="Space"
      >
        <div
          className={styles.progressFill}
          style={{ width: `${progress}%` }}
          role="progressbar"
          aria-valuenow={Math.round(progress)}
          aria-valuemin={0}
          aria-valuemax={100}
          aria-label={`Hold to confirm ${label}`}
        />
        <div className={styles.content}>
          <Text variant="text-body-medium" as="span" className={styles.label}>{label}</Text>
          {subtext && <Text variant="text-body-small" as="span" className={styles.subtext}>{subtext}</Text>}
        </div>
      </button>
    );
  }
);

DestructiveMenuItem.displayName = 'DestructiveMenuItem';

.destructiveMenuItem {
  display: flex;
  align-items: center;
  padding: var(--dimension-space-075);
  background-color: transparent;
  border: none;
  border-radius: var(--dimension-radius-075);
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  text-align: left;
  width: 100%;
  min-height: var(--dimension-size-400);
  position: relative;
  transition: var(--effect-transition-interaction-background-instant);
  overflow: hidden;
}

.destructiveMenuItem:has(.subtext) { align-items: flex-start; }

.progressFill {
  position: absolute;
  top: 0;
  left: 0;
  bottom: 0;
  background-color: var(--color-background-faint-negative);
  border-radius: var(--dimension-radius-075);
  transition: width 0ms linear;
  pointer-events: none;
  z-index: 0;
}

.destructiveMenuItem::before {
  content: '';
  position: absolute;
  inset: 0;
  background-color: transparent;
  border-radius: var(--dimension-radius-075);
  transition: var(--effect-transition-interaction-background-instant);
  pointer-events: none;
  z-index: 1;
}

.content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  gap: var(--dimension-space-025);
  min-width: 0;
}

.label { color: var(--color-foreground-bold-negative); }
.subtext { color: var(--color-foreground-secondary); text-wrap: pretty; }

.destructiveMenuItem:hover::before { background-color: var(--color-interaction-hover); }
.destructiveMenuItem:active::before { background-color: transparent; }
